head.script:
scwin.strToDate = $c.date.getServerDateTime();
scwin.strFrDate = $c.date.addDate($c.date.addMonth(scwin.strToDate, -1), 1);

//---------------------------
// param
//---------------------------
scwin.blno = "";
scwin.intendDt = "";
scwin.kcomcd = "";
scwin.prtnGrpNo = "";
scwin.seaair = "";
scwin.iogb = "";
scwin.bilgClntNo = "";
scwin.userId = "";
scwin.type = "";
scwin.rmk = "";
scwin.remark = "";
scwin.eng = "";
scwin.locPtnCls = "";
scwin.pic = "";
scwin.summary = "";

//---------------------------
// Hidden Object
//---------------------------
scwin.ed_sumAmtAll = "";
scwin.ed_susRecvSellAmtTot = 0;
scwin.ed_susRecvSellAmt = 0;
scwin.ed_susRecvSellRtnDrAmt = 0;
scwin.hid_summary = "";
scwin.hid_goods = "";

//---------------------------
// Function
//---------------------------
scwin.saveflag = "FALSE"; // 저장상태구분
scwin.bilgAmt = 0;
scwin.bilgAmtFcrc = 0;
scwin.fcrcBilgAmt = 0;

scwin.sumAmtAll = 0; //매출합계금액
scwin.cashSellAmt = 0; //현금매출액
scwin.susRecvSellRtnDrAmt = 0;//가수금매출환불차변금액
scwin.susRecvSellAmt = 0; //가수금매출금액
scwin.susRecvSellAmtTot = 0; //가수금매출금액+가수금매출환불차변금액
scwin.cashRtnAmt = 0; //현금환불금액
scwin.clntMgntYn = 0;

scwin.susRecvInitamtClsCd = "01";
scwin.offsetNo1 = ""; //역분개 여부

scwin.onpageload = function () {
    scwin.blno = $c.util.isEmpty($c.data.getParameter("blno")) ? "" : $c.data.getParameter("blno"); 
    scwin.intendDt = $c.util.isEmpty($c.data.getParameter("intendDt")) ? "" : $c.data.getParameter("intendDt"); 
    scwin.kcomcd = $c.util.isEmpty($c.data.getParameter("kcomcd")) ? "" : $c.data.getParameter("kcomcd"); 
    scwin.prtnGrpNo = $c.util.isEmpty($c.data.getParameter("prtnGrpNo")) ? "" : $c.data.getParameter("prtnGrpNo"); 
    scwin.seaair = $c.util.isEmpty($c.data.getParameter("seaair")) ? "" : $c.data.getParameter("seaair"); 
    scwin.iogb = $c.util.isEmpty($c.data.getParameter("iogb")) ? "" : $c.data.getParameter("iogb"); 
    scwin.bilgClntNo = $c.util.isEmpty($c.data.getParameter("bilgClntNo")) ? "" : $c.data.getParameter("bilgClntNo"); 
    scwin.userId = $c.util.isEmpty($c.data.getParameter("userId")) ? "" : $c.data.getParameter("userId"); 
    scwin.type = $c.util.isEmpty($c.data.getParameter("type")) ? "" : $c.data.getParameter("type"); 
    scwin.rmk = $c.util.isEmpty($c.data.getParameter("rmk")) ? "" : $c.data.getParameter("rmk"); 
    scwin.remark = $c.util.isEmpty($c.data.getParameter("remark")) ? "" : $c.data.getParameter("remark"); 
    scwin.eng = $c.util.isEmpty($c.data.getParameter("eng")) ? "" : $c.data.getParameter("eng"); 
    scwin.locPtnCls = $c.util.isEmpty($c.data.getParameter("locPtnCls")) ? "" : $c.data.getParameter("locPtnCls"); 
    scwin.pic = $c.util.isEmpty($c.data.getParameter("pic")) ? "" : $c.data.getParameter("pic"); 
    scwin.summary = $c.util.isEmpty($c.data.getParameter("summary")) ? "" : $c.data.getParameter("summary");  

    const arrParent = $p.getAllParameter().paramData.data;
    //ds_temp.setJSON(arrParent[0]);

    //DataSet 복사
    $c.gus.cfCopyDataSet(arrParent[0], ds_certiCommonDs2, "copyHeader=yes");

    scwin.f_copyDataSetHeader(ds_certiCommonDs2, ds_certiCommonDs);

    // scwin.hid_summary = arrParent[1]; //매출항목
    // scwin.hid_goods = arrParent[1]; //매출항목
    scwin.hid_summary = arrParent[1];
    scwin.hid_goods = arrParent[1];

    // Radio Value - 청구/영수
    ds_certiCommonDs.setCellData(0, "receptClsCd", "02");

    if(scwin.blno != ""){
        ed_summary.setValue(scwin.blno);    
    }

    $c.gus.cfEnableObj(ica_slipCloseYm, false);
    $c.gus.cfEnableObj(ica_taxCloseYm, false);
    $c.gus.cfEnableObj(ed_collMoneyAcctDeptCd, false);

    scwin.f_Retrieve();

    scwin.offsetNo1 = ds_certiCommonDs.getCellData(0, "offsetNo1");
};


//-------------------------------------------------------------------------
// Function
//-------------------------------------------------------------------------
scwin.f_copyDataSetHeader = function (oOriginDataSet, oTargetDataSet) {
    oTargetDataSet.setJSON(oOriginDataSet.getAllJSON());
};

scwin.f_Retrieve = async function () {
    let e = await $c.sbm.execute(sbm_retrieve);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_retrieve_submitdone(e);
    }

    scwin.f_ButtonEnable();
};

// Button Enable/ Disable
scwin.f_ButtonEnable = async function () {
    // 세금계산서 생성여부
    if (ds_evidenceDs.getCellData(0, "sellVatNo") != null && ds_evidenceDs.getCellData(0, "sellVatNo").length > 1){
        $c.gus.cfDisableBtn([btn_save]);
        $c.gus.cfEnableBtnOnly([btn_del]);
    } else {
        $c.gus.cfDisableBtn([btn_del]);
        $c.gus.cfEnableBtnOnly([btn_save]);
    }
};

// 화면종료시
scwin.f_OnUnload = function () {
    var arrRtnVal = new Array(1);

    arrRtnVal[0] = ds_evidenceDs.getCellData(0, "sellVatNo");
    arrRtnVal[1] = scwin.saveflag;

    window.returnValue = arrRtnVal;
    $c.win.closePopup(arrRtnVal); 
};

scwin.f_Save = async function (){
    // 청구일 경우 매출입구분이 영수매출인 경우는 세금계산서 생성 불가 2011.06.22
    if (rd_receptClsCd.getValue() == "02"){
        if (ds_evidenceDs.getCellData(0, "receiveSellingYn") == "1") {
            await $c.gus.cfAlertMsg("청구할 수 없는 영수매출 거래처입니다.\n다시 확인하십시오!");
            return;
        }
    }

    // 가수금인 경우 가수금의 입금일자가 전표일자보다 크면 세금계산서 생성 불가 2016.12.12
    var chkSlipMm = ica_slipDt.getValue().substring(0, 6);
    var chkSusMn = "";
    if (ds_collMoney.getRowCount() > 0) {
        for (var i = 0; i < ds_collMoney.getRowCount(); i++) {
            chkSusMn = ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt").substring(0, 6);
            if(chkSusMn > chkSlipMm){
                await $c.gus.cfAlertMsg("가수금의 입금월은 전표월보다 이전이거나 같아야 합니다. \n다시 확인하십시오.");
                return;
            }
        }
    }

    // 필수입력항목 체크
    if (rd_receptClsCd.getValue() == "01") {
        ds_evidenceDs.setCellData(0, "collMoneyAcctDeptCd", ds_evidenceDs.getCellData(0, "acctDeptCd"));
        ed_collMoneyAcctDeptCd.setValue(ds_evidenceDs.getCellData(0, "acctDeptCd"));
    } else {
        if ($c.gus.cfIsNull(ed_collMoneyAcctDeptCd.getValue())) {
            ed_collMoneyAcctDeptCd.setValue(ds_evidenceDs.getCellData(0, "acctDeptCd"));
        }
    }

    ds_evidenceDs.setCellData(1, "collMoneyAcctDeptCd", ed_collMoneyAcctDeptCd.getValue());

    // 공급일자, 전표일자, 수금부서, 적요(비고), 품명
    if (!$c.gus.cfValidate([ica_spplyDt, ica_slipDt, ed_collMoneyAcctDeptCd, ed_summary, ed_goods])) {
        return;
    }

    ds_evidenceDs.setCellData(0, "fmlaClsCd", "01");	// 거래명세서 : 01, Bill : 02
    ds_evidenceDs.setCellData(0, "evidRglClsCd", "01");	// 세금계산서 상태 : 01 '정상', 02 '적자', 99 '삭제'
    ds_evidenceDs.setCellData(0, "spplyDt", ica_spplyDt.getValue());	
    ds_evidenceDs.setCellData(0, "slipDt", ica_slipDt.getValue());
    ds_evidenceDs.setCellData(0, "summary", ed_summary.getValue());
    ds_evidenceDs.setCellData(0, "goods", ed_goods.getValue());
    ds_evidenceDs.setCellData(0, "receptClsCd", rd_receptClsCd.getValue()); // 영수/청구
    ds_evidenceDs.setCellData(0, "chk", ds_ctrt.getCellData(0, "sellLodeptCd"));

    if (rd_receptClsCd.getValue() == "01") {
        //수금 내역 금액 검증
        if(!scwin.f_chkAmt()){
            await $c.gus.cfAlertMsg("수금정보의 금액항목 오류입니다.\n다시 확인하십시오.");
            return;
        }
        // 환불(전도금-현금)계정이 발생하면 에러처리 2011.07.01
        if (ed_cashRtnAmt.getValue() != 0) {
            await $c.gus.cfAlertMsg("전도금계정 전표는 생성할 수 없습니다.\n다시 확인하십시오.");
            return;
        }
        if(!await $c.win.confirm(MSG_CM_CRM_001)) 
            return;
        ds_evidenceDs.setCellData(0, "cashSellAmt", ed_cashSellAmt.getValue());
        ds_evidenceDs.setCellData(0, "susRecvSellRtnDrAmt", scwin.txt_susRecvSellRtnDrAmt);
        ds_evidenceDs.setCellData(0, "susRecvSellAmt", scwin.txt_susRecvSellAmt);
        ds_evidenceDs.setCellData(0, "cashRtnAmt", ed_cashRtnAmt.getValue());
        ds_evidenceDs.setCellData(0, "susRecvInitamtClsCd", acb_susRecvInitamtClsCd.getValue());
    } else{
        if(!await $c.win.confirm(MSG_CM_CRM_001)) 
            return;
        ds_evidenceDs.setCellData(0, "bilgAmt", scwin.bilgAmt);
        ds_evidenceDs.setCellData(0, "bilgAmtFcrc", scwin.bilgAmtFcrc);
        ds_evidenceDs.setCellData(0, "fcrcBilgAmt", scwin.fcrcBilgAmt);
    }

    var odi1 = "01";
    var odi2 = ds_certiCommonDs.getCellData(0, "inscrpFmlaPatternCd");
    var url = f_createUrl("/ds/fs/ja_fs_202_06_10_"+ odi1 + "_" + odi2 + ".ozr", "ja_fs_202_06_10_" + odi1 + "_" + odi2 + ".odi", scwin.f_createParam());
    ds_certiCommonDs.setCellAllData(0, "url", url);

    // Insert를 위해서 DataSet 복사 : ds_evidenceDs -> ds_evidenceContDs
    $c.gus.cfCopyDataSet(ds_evidenceDs, ds_evidenceContDs, "copyHeader=yes");

    let e = await $c.sbm.execute(sbm_master);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_master_submitdone(e);
    } 

    scwin.f_ButtonEnable();
};

scwin.f_createUrl = function(ozrFileNm, odiFileNm, ozParam) {
    var url = "";

    url = "http://ebiz.debis.co.kr/common/jsp/external_interface.jsp?"
    + "SYS_CD=OSIDE_CERTI&certiOzrFileNm=" + ozrFileNm
    + "&certiOdiFileNm=" + odiFileNm
    + "&certiOzParam=" + ozParam;

    return url;
};

// 전자세금계산서 발행시 보여질 레포트 PARAM 생성
scwin.f_createParam = function() {
    var param = "";

    param = "bilgLodeptCd=" 		+ ds_certiCommonDs.getCellData(0, "bilgLodeptCd")
            + ",bilgClntNo=" 		+ ds_certiCommonDs.getCellData(0, "bilgClntNo")
            + ",qryConKnd=" 		+ "02"
            + ",confirmDtFm=" 		+ ""
            + ",confirmDtTo="		+ ""
            + ",spplyDtFm="			+ ""
            + ",spplyDtTo="			+ ""
            + ",modId="				+ ""
            + ",printFg="			+ ""
            + ",certiAggregateFg=" 	+ ""
            + ",dcsnClsCd="			+ ""
            + ",certiNo="			+ ds_certiCommonDs.getCellData(0, "certiNo")
            + ",fmlaClsCd="			+ ds_certiCommonDs.getCellData(0, "fmlaClsCd")
            + ",fmlaPatternCd=" 	+ ds_certiCommonDs.getCellData(0, "fmlaPatternCd")
            + ",upperFmlaClsCd=" 	+ ""
            + ",upperFmlaPatternCd=" + ""
            + ",sellVatNo=" 		+ ""
            + ",inscrpFmlaClsCd=" 	+ ds_certiCommonDs.getCellData(0, "inscrpFmlaClsCd")
            + ",inscrpFmlaPatternCd=" + ds_certiCommonDs.getCellData(0, "inscrpFmlaPatternCd")
            + ",spplyFg=" 			+ lc_spplyFg.getValue()
            + ",ozNo=" 				+ lc_ozNo.getValue()
            + ",sumGbn="			+ (cbx_sumCheck.getValue() == "Y" ? "Y" : "N")
            + ",wtGbn="				+ (cbx_wt.getValue() == "Y" ? "Y" : "N")
            + ",coCd="				+ ds_certiCommonDs.getCellData(0, "coCd")	// 회사코드
            ;
    return param;  				
};

// 삭제
scwin.f_Delete = async function () {
    var msg = $c.data.getMessage(MSG_CM_CRM_008,['세금계산서(' + ds_evidenceDs.getCellData(0, "sellVatNo") + ')']);
    if(!await $c.win.confirm(msg)) {
        return;
    }

    if (scwin.offsetNo1 != "") {
        await $c.gus.cfAlertMsg("역분개된 세금계산서입니다. 거래명세서번호에 'A01'을 붙인 거래명세서번호로 조회하여 작업하십시오.\n\n(예: 거래명세서번호가 'V500068317'인 경우 'V500068317A01'조회)");
        return;
    }

    ds_evidenceDs.setCellData(0, "fmlaClsCd", "01");	//거래명세서 : 01, Bill : 02

    if (ds_evidenceDs.getCellData(0, "postDt").substring(0, 6) <= ica_slipCloseYm.getValue() && ds_evidenceDs.getCellData(0, "postDt").trim()!="") {
        var msg = "마감완료된 전표 이므로  역전표 생성 됩니다. 마감기간일 경우 마감이 완전히 끝났는지 확인하시고, 작업하십시요!";
        if (!await $c.win.confirm(msg)){					
            return; 
        }	
    }

    if (!await scwin.f_CheckTaxCancelSpplyDt()) 
        return;

    ds_evidenceDs.setCellData(0, "cancelSpplyDt", ica_cancelSpplyDt.getValue());

    if (ds_evidenceDs.getCellData(0, "receptClsCd") == '02') {
        sbm_DeleteCerti.action = "/ja.ds.fs.bilg.bilg.JaDeleteTaxInvoiceCMD.do";
    } else if (ds_evidenceDs.getCellData(0, "receptClsCd") == '01') {
        sbm_DeleteCerti.action = "/ja.ds.fs.bilg.bilg.JaDeleteReceiptTaxInvoiceCMD.do";
    }

    let e = await $c.sbm.execute(sbm_DeleteCerti);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_DeleteCerti_submitdone(e);
    } 

    scwin.f_ButtonEnable();
};

// 세금계산서 취소 때  세무마감여부 CHECK
scwin.f_CheckTaxCancelSpplyDt = async function () {
    var taxCloseYm  = ica_taxCloseYm.getValue();
    var spplyYm		= ica_spplyDt.getValue().substring(0, 6);
    var isTrue;

    if (taxCloseYm >= spplyYm) {
        isTrue = await $c.win.confirm("세무마감된 계산서를 취소할 경우에는 반드시 거래처에 수정세금계산서를 발행해야 합니다.(거래처와 합의 요함)\n\n세금계산서 및 전표를 취소하시겠습니까?")

        if (!isTrue) return;

        if ($c.gus.cfIsNull(ica_cancelSpplyDt.getValue())) { 
            if (await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["[수정세금계산서 공급일자 ]"])) { //@은(는) 필수 입력 항목입니다
                ica_cancelSpplyDt.focus();
                return false;
            } 
        }
        if (!await $c.gus.cfValidate([ica_cancelSpplyDt])) {
            ica_cancelSpplyDt.focus();
            return;
        }
    }
    return true;
};

// 가수금 내역 팝업창 처리
scwin.f_susRecvPop = async function () {
    if (rd_receptClsCd.getValue() != "01") {
        await $c.gus.cfAlertMsg("영수 세금계산서 생성시만 가수금 계정을 책정할 수 있습니다.");
        return;
    }

    tbx_susRecvSellAmtTot.setValue(0);
    scwin.f_setAmtSusRecvSellAmtTot();
    ds_collMoney.removeAll();

    var valueObject = new Object();
    valueObject.prov = ds_collMoney;
    valueObject.fromDate = scwin.strFrDate;
    valueObject.toDate = scwin.strToDate;
    valueObject.clsCd = acb_susRecvInitamtClsCd.getValue() == "01" ? "2" : "3";	// 1:가수금/선수금, 2:가수금, 3:선수금
    valueObject.clntNo = ed_bilgClnt.getValue();
    valueObject.bankbookNo = "";		//통장번호 -> 필요없을경우 Setting 안해도됨.;

    let win_url = "/ui/ac/fm/collmoneymgnt/rcptmgnt/fm_502_03_00p.xml";
    let data = {
        prov : ds_collMoney,
        fromDate : scwin.strFrDate,
        toDate : scwin.strToDate,
        clsCd : acb_susRecvInitamtClsCd.getValue() == "01" ? "2" : "3",
        clntNo : ed_bilgClnt.getValue(),
        bankbookNo : ""
    };
    data.valueObject = valueObject;

    let opts = {
        id        : "smpPop"
        , popupName : "가수금/선수금POPUP화면"
        , modal     : true
        , type      : "browserPopup"
        , width     : 1120
        , height    : 560
        , title     : "가수금/선수금POPUP"
    };

    var rtnList = await $c.win.openPopup(win_url, opts, data);

    var remainAmt = 0;
    for (var i = 0; i < ds_collMoney.getRowCount(); i++){
        remainAmt += Number(ds_collMoney.getCellData(i, "remainAmt"));
    }


  //  tbx_susRecvSellAmtTot.setValue($c.gus.cfInsertComma(remainAmt)); 
    tbx_susRecvSellAmtTot.setValue(remainAmt); 
    scwin.f_setAmtSusRecvSellAmtTot();
};

// 금액계산 가수금액 입력시
scwin.f_setAmtSusRecvSellAmtTot = function () {
    scwin.f_setMethAmt();

    scwin.susRecvSellAmt = scwin.sumAmtAll - scwin.susRecvSellAmtTot >= 0 ? scwin.susRecvSellAmtTot : scwin.sumAmtAll;
    scwin.susRecvSellRtnDrAmt = scwin.susRecvSellAmtTot - scwin.susRecvSellAmt;
    scwin.cashRtnAmt = scwin.susRecvSellRtnDrAmt;

    scwin.ed_susRecvSellRtnDrAmt  = scwin.susRecvSellRtnDrAmt; 
    scwin.ed_susRecvSellAmt       = scwin.susRecvSellAmt;	

    ed_cashRtnAmt.setValue(scwin.cashRtnAmt);
    tbx_sumAmtDtl.setValue(scwin.cashSellAmt + scwin.susRecvSellAmtTot);
    ed_cashSellAmtCon.setValue(scwin.sumAmtAll - scwin.susRecvSellRtnDrAmt - scwin.susRecvSellAmt + scwin.cashRtnAmt);


};

// 금액계산 입력시 검증
scwin.f_chkAmt = function () {
    scwin.f_setMethAmt();

    if(scwin.sumAmtAll == scwin.cashSellAmt + scwin.susRecvSellRtnDrAmt + scwin.susRecvSellAmt - ((scwin.susRecvSellRtnDrAmt + scwin.cashRtnAmt) / 2)) {
        return true;
    } else {
        return false;
    }
};

// 금액계산
scwin.f_setMethAmt = function () {
    scwin.sumAmtAll 			= scwin.ed_sumAmtAll;
    scwin.cashSellAmt 		    = ed_cashSellAmt.getValue();
    scwin.susRecvSellRtnDrAmt   = scwin.ed_susRecvSellRtnDrAmt;
    scwin.susRecvSellAmt 		= scwin.ed_susRecvSellAmt;
    scwin.susRecvSellAmtTot 	= tbx_susRecvSellAmtTot.getValue();
    scwin.cashRtnAmt 			= ed_cashRtnAmt.getValue();


    scwin.sumAmtAll 			= Number(scwin.sumAmtAll);
    scwin.cashSellAmt 		    = Number(scwin.cashSellAmt);
    scwin.susRecvSellRtnDrAmt   = Number(scwin.susRecvSellRtnDrAmt);
    scwin.susRecvSellAmt 		= Number(scwin.susRecvSellAmt);
    scwin.susRecvSellAmtTot 	= Number(scwin.susRecvSellAmtTot);
    scwin.cashRtnAmt 			= Number(scwin.cashRtnAmt);
};

// 금액계산 현금 매출액 입력시
scwin.f_setAmtCashSellAmt = function () {
    scwin.f_setMethAmt();

    tbx_sumAmtDtl.setValue($c.gus.cfInsertComma(scwin.cashSellAmt + scwin.susRecvSellAmtTot));
    ed_cashSellAmtCon.setValue(scwin.sumAmtAll - scwin.susRecvSellRtnDrAmt - scwin.susRecvSellAmt + scwin.cashRtnAmt);
};

//-------------------------------------------------------------------------
// Event onClick
//-------------------------------------------------------------------------
// 닫기 클릭이벤트
