    scwin.f_setAmtCashSellAmt();
};

//-------------------------------------------------------------------------
// Event onchange
//-------------------------------------------------------------------------
scwin.rd_receptClsCd_onchange = function (info) {
	if (rd_receptClsCd.getValue() == "01") {	// 영수
        ed_bilgAmt.setValue(0);
        ed_cashSellAmt.setValue(0);
        tbx_susRecvSellAmtTot.setValue($c.gus.cfInsertComma(0));
		scwin.ed_susRecvSellAmt = 0;
		scwin.susRecvSellRtnDrAmt = 0;
        tbx_sumAmtDtl.setValue($c.gus.cfInsertComma(0));
        ed_cashRtnAmt.setValue(0);
        ed_cashSellAmt.setReadOnly(true);
        acb_susRecvInitamtClsCd.setReadOnly(false);
        ed_cashSellAmtCon.setValue(scwin.sumAmtAll);

		ica_spplyDt.setValue(scwin.strToDate);
		ica_slipDt.setValue(scwin.strToDate); 
	} else { // 청구
        ed_bilgAmt.setValue(scwin.bilgAmt);
		ed_cashSellAmt.setValue(0);
        tbx_susRecvSellAmtTot.setValue($c.gus.cfInsertComma(0));
		scwin.ed_susRecvSellAmt = 0;
		scwin.susRecvSellRtnDrAmt = 0;

		tbx_sumAmtDtl.setValue($c.gus.cfInsertComma(0));
		ed_cashRtnAmt.setValue(0);
        ed_cashSellAmtCon.setValue(0);
		ed_cashSellAmt.setReadOnly(true);
        acb_susRecvInitamtClsCd.setReadOnly(true)
		ica_slipDt.setReadOnly(false);
    }
};

scwin.acb_susRecvInitamtClsCd_onchange = function (info) {
	if(scwin.susRecvInitamtClsCd != acb_susRecvInitamtClsCd.getValue()){
		scwin.susRecvInitamtClsCd = acb_susRecvInitamtClsCd.getValue();
		scwin.ed_susRecvSellAmtTot = 0;
        tbx_susRecvSellAmtTot.setValue($c.gus.cfInsertComma(0));
		scwin.f_setAmtSusRecvSellAmtTot();
		ds_collMoney.removeAll();
	}
};

//-------------------------------------------------------------------------
// Sbm submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = function (e) {
    // 세금계산서 번호 정보
	tbx_sellVatNo.setValue(ds_evidenceDs.getCellData(0, "sellVatNo"));  // 세금계산서번호
    tbx_offsetVatNo.setValue(ds_evidenceDs.getCellData(0, "offsetVatNo"));
	tbx_certiNo.setValue(ds_evidenceDs.getCellData(0, "certiNo"));      // 거래명세서번호
	tbx_crn.setValue(ds_evidenceDs.getCellData(0, "crn"));              // 사업자번호
	ed_busiNm.setValue(ds_evidenceDs.getCellData(0, "busiNm"));         // 상호
	tbx_repstNm.setValue(ds_evidenceDs.getCellData(0, "repstNm"));      // 대표자
	ica_spplyDt.setValue(ds_evidenceDs.getCellData(0, "spplyDt"));      // 공급일자
	tbx_taxnClsCd.setValue(ds_evidenceDs.getCellData(0, "taxnClsCd") + " (" + ds_evidenceDs.getCellData(0, "taxnClsNm") + ")"); // 부가세구분

    // 매출확정 정보
    tbx_bilgLodept.setValue(ds_evidenceDs.getCellData(0, "bilgLodeptCd") + " " + ds_evidenceDs.getCellData(0, "bilgLobranNm")); // 청구부서
    tbx_slipNo.setValue(ds_evidenceDs.getCellData(0, "slipNo")); // 전표번호
    tbx_offsetNo.setValue(ds_evidenceDs.getCellData(0, "offsetNo"));
    ica_slipDt.setValue(ds_evidenceDs.getCellData(0, "slipDt")); // 전표생성일자
    tbx_dcsnClsNm.setValue(ds_evidenceDs.getCellData(0, "dcsnClsNm"));

	if (ds_evidenceDs.getCellData(0, "receptClsCd")=="") {
		rd_receptClsCd.setValue("02");
	} else {
		rd_receptClsCd.setValue(ds_evidenceDs.getCellData(0, "receptClsCd")); // 청구/영수
	}

    tbx_adptExchRt.setValue(ds_evidenceDs.getCellData(0, "adptExchRt")); // 환율
	tbx_spplyAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "spplyAmt"))); // 원화공급액
	tbx_spplyAmtFcrc.setValue(ds_evidenceDs.getCellData(0, "spplyAmtFcrc")); // 외화매출액


    tbx_vatAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "vatAmt"))); // 부가세
    tbx_sumAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "sumAmt"))); // 금액합계
    scwin.ed_sumAmtAll = Number(ds_evidenceDs.getCellData(0, "sumAmt")) + Number(ds_evidenceDs.getCellData(0, "fireInsrRateAmt"));
    scwin.sumAmtAll = Number(ds_evidenceDs.getCellData(0, "sumAmt")) + Number(ds_evidenceDs.getCellData(0, "fireInsrRateAmt"));
	tbx_fireInsrRateAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "fireInsrRateAmt"))); // 기타금액

    if (ds_evidenceDs.getCellData(0, "sellVatNo") != null && ds_evidenceDs.getCellData(0, "sellVatNo").length > 1){ // 세금계산서 생성여부
		ed_summary.setValue(ds_evidenceDs.getCellData(0, "summary")); //저장된 적요
	} else { //적요에 파라미터로 넘어온 BL번호 기재
		if (scwin.blno != "") {
			ed_summary.setValue(scwin.blno);
			if (scwin.summary != "") {
			    ed_summary.setValue(scwin.blno + "(" + scwin.summary + ")");
			}
        }
	}
    ed_goods.setValue(ds_evidenceDs.getCellData(0, "goods")); // 품명

    // 수금 정보
	ed_collMoneyAcctDeptCd.setValue(ds_evidenceDs.getCellData(0, "collMoneyAcctDeptCd")); // 수금부서 코드
	ed_collMoneyAcctDeptNm.setValue(ds_evidenceDs.getCellData(0, "collMoneyAcctDeptNm")); // 수금부서 명
	ed_bilgClnt.setValue(ds_evidenceDs.getCellData(0, "bilgClntNo"));   // 거래처코드
	ed_bilgClntNm.setValue(ds_evidenceDs.getCellData(0, "bilgClntNm"));	// 거래처명

    // 수금내역
    scwin.bilgAmt		= 0;
    scwin.bilgAmtFcrc	= 0;
    scwin.fcrcBilgAmt	= 0;

   	for (var i = 0; i < ds_ctrt.getRowCount(); i++) {
    	scwin.bilgAmt		+= Number(ds_ctrt.getCellData(i, "bilgAmt"));
    	scwin.bilgAmtFcrc	+= Number(ds_ctrt.getCellData(i, "bilgAmtFcrc"));
    	scwin.fcrcBilgAmt	+= Number(ds_ctrt.getCellData(i, "fcrcBilgAmt"));
   	}

   	scwin.bilgAmt = scwin.bilgAmt + Number(ds_evidenceDs.getCellData(0, "fireInsrRateAmt"));
   	ed_bilgAmt.setValue(scwin.bilgAmt); // 외상매출금

    ed_cashSellAmt.setValue(ds_evidenceDs.getCellData(0, "cashSellAmt")); // 현금매출금액

	acb_susRecvInitamtClsCd.setValue(ds_evidenceDs.getCellData(0, "susRecvInitamtClsCd")); // 선/가수금구분코드
	scwin.susRecvInitamtClsCd = ds_evidenceDs.getCellData(0, "susRecvInitamtClsCd");

    tbx_susRecvSellAmtTot.setValue($c.gus.cfInsertComma(Number(ds_evidenceDs.getCellData(0, "susRecvSellRtnDrAmt")) + Number(ds_evidenceDs.getCellData(0, "susRecvSellAmt"))));	// 무통장입금 가수금
	tbx_sumAmtDtl.setValue($c.gus.cfInsertComma(Number(ds_evidenceDs.getCellData(0, "cashSellAmt")) + Number(ds_evidenceDs.getCellData(0, "susRecvSellRtnDrAmt")) + Number(ds_evidenceDs.getCellData(0, "susRecvSellAmt")) + Number(ds_evidenceDs.getCellData(0, "pldgAmt")))); // 합계
	ed_cashRtnAmt.setValue(ds_evidenceDs.getCellData(0, "cashRtnAmt")); //환불(전도현금)

	ica_slipCloseYm.setValue(ds_evidenceDs.getCellData(0, "slipCloseYm")); // 회계마감월
	ica_taxCloseYm.setValue(ds_evidenceDs.getCellData(0, "taxCloseYm"));   // 세무마감월

	if ($c.gus.cfIsNull(ds_evidenceDs.getCellData(0, "slipNo"))){
		if (scwin.blno != "") {
			ed_summary.setValue(scwin.blno);
			if (scwin.summary !="") {
			    ed_summary.setValue(scwin.blno + "(" + scwin.summary + ")");
			}
		} else {
            if(ds_evidenceDs.getCellData(0, "bilgClntNo") == '310617' || ds_evidenceDs.getCellData(0, "bilgClntNo") == '310618' || ds_evidenceDs.getCellData(0, "bilgClntNo") == '310619' || ds_evidenceDs.getCellData(0, "bilgClntNo") == '294268') { // 한화큐셀 ,현대에너지솔루션 일 경우 BL번호 세팅
                ed_summary.setValue(ds_certiCommonDs.getCellData(0, "blNo"));
            } else if(ds_evidenceDs.getCellData(0, "fmlaPatternCd") == "05") { //거래명세서유형 : 수입통관운송
                ed_summary.setValue(scwin.hid_summary + "(" + ds_certiCommonDs.getCellData(0, "blNo") + ")");	//매출항목(blNo)
            } else {
                ed_summary.setValue(scwin.hid_summary);	//매출항목
            }
        }

        if (ds_evidenceDs.getCellData(0, "bilgClntNo") == '310617' || ds_evidenceDs.getCellData(0, "bilgClntNo") == '310618' || ds_evidenceDs.getCellData(0, "bilgClntNo") == '310619' || ds_evidenceDs.getCellData(0, "bilgClntNo") == '294268') { // 한화큐셀,현대에너지솔루션  일 경우 매출항목  세팅
            ed_goods.setValue(scwin.hid_goods);
        } else if (ds_evidenceDs.getCellData(0, "fmlaPatternCd") == "05") { //거래명세서유형 : 수입통관운송
            ed_goods.setValue(ed_summary.getValue()); // 매출항목(blNo)
        } else {
            ed_goods.setValue(scwin.hid_goods);	// 매출항목
        }

		ica_spplyDt.setValue(scwin.strToDate);
		if (scwin.intendDt !="") {
			ica_spplyDt.setValue(scwin.intendDt);
		}
		ica_slipDt.setValue(scwin.strToDate);
	} else {
        rd_receptClsCd.setDisabled(true);
	}	
};

scwin.sbm_master_submitdone = async function (e) {
    if(await $c.gus.cfAlertMsg(MSG_CM_INF_001)){
        scwin.saveflag = "TRUE";

        tbx_sellVatNo.setValue(ds_evidenceDs.getCellData(0, "sellVatNo")); // 세금계산서번호
        tbx_certiNo.setValue(ds_evidenceDs.getCellData(0, "certiNo")); // 거래명세서번호
        tbx_crn.setValue(ds_evidenceDs.getCellData(0, "crn")); // 사업자번호
        ed_busiNm.setValue(ds_evidenceDs.getCellData(0, "busiNm")); // 상호
        tbx_repstNm.setValue(ds_evidenceDs.getCellData(0, "repstNm")); // 대표자
        ica_spplyDt.setValue(ds_evidenceDs.getCellData(0, "spplyDt")); // 공급일자
        tbx_taxnClsCd.setValue(ds_evidenceDs.getCellData(0, "taxnClsCd") + " (" + ds_evidenceDs.getCellData(0, "taxnClsNm") + ")"); // 부가세구분
        ed_collMoneyAcctDeptCd.setValue(ds_evidenceDs.getCellData(0, "collMoneyAcctDeptCd"));	//수금부서 코드
        ed_collMoneyAcctDeptNm.setValue(ds_evidenceDs.getCellData(0, "collMoneyAcctDeptNm"));	//수금부서 명
        ed_bilgClnt.setValue(ds_evidenceDs.getCellData(0, "bilgClntNo"));   // 거래처
        ed_bilgClntNm.setValue(ds_evidenceDs.getCellData(0, "bilgClntNm"));	// 거래처
        tbx_bilgLodept.setValue(ds_evidenceDs.getCellData(0, "bilgLodeptCd") + " " + ds_evidenceDs.getCellData(0, "bilgLobranNm"));	// 청구부서
        tbx_slipNo.setValue(ds_evidenceDs.getCellData(0, "slipNo")); // 전표번호
        ica_slipDt.setValue(ds_evidenceDs.getCellData(0, "slipDt")); // 전표생성일자
        rd_receptClsCd.setValue(ds_evidenceDs.getCellData(0, "receptClsCd")); // 청구/영수
        tbx_adptExchRt.setValue(ds_evidenceDs.getCellData(0, "adptExchRt")); // 환율

        tbx_spplyAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "spplyAmt"))); //원화공급액
        tbx_spplyAmtFcrc.setValue(ds_evidenceDs.getCellData(0, "spplyAmtFcrc")); //외화매출액
        tbx_vatAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "vatAmt"))); // 부가세
        tbx_fireInsrRateAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "fireInsrRateAmt"))); // 화재보험표

        ed_summary.setValue(ds_evidenceDs.getCellData(0, "summary")); // 적요
        tbx_dcsnClsNm.setValue(ds_evidenceDs.getCellData(0, "dcsnClsNm")); // 상태

        if (scwin.intendDt != "") {
            ica_spplyDt.setValue(scwin.intendDt);
        }

        ed_goods.setValue(ds_evidenceDs.getCellData(0, "goods")); // 적요

        tbx_sumAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "sumAmt"))); // 화재보험표
        scwin.ed_sumAmtAll = Number(ds_evidenceDs.getCellData(0, "sumAmt")) + Number(ds_evidenceDs.getCellData(0, "fireInsrRateAmt"));
        scwin.sumAmtAll = Number(ds_evidenceDs.getCellData(0, "sumAmt")) + Number(ds_evidenceDs.getCellData(0, "fireInsrRateAmt"));
        acb_susRecvInitamtClsCd.setValue(ds_evidenceDs.getCellData(0, "susRecvInitamtClsCd")); // 선/가수금구분코드
        scwin.susRecvInitamtClsCd = ds_evidenceDs.getCellData(0, "susRecvInitamtClsCd");

        ed_bilgAmt.setValue(ds_evidenceDs.getCellData(0, "bilgAmt"));
        ed_cashSellAmt.setValue(ds_evidenceDs.getCellData(0, "cashSellAmt")); // 현금매출금액

        tbx_susRecvSellAmtTot.setValue($c.gus.cfInsertComma(Number(ds_evidenceDs.getCellData(0, "susRecvSellRtnDrAmt")) + Number(ds_evidenceDs.getCellData(0, "susRecvSellAmt")))); // 무통장입금
        tbx_sumAmtDtl.setValue($c.gus.cfInsertComma(Number(ds_evidenceDs.getCellData(0, "cashSellAmt")) + Number(ds_evidenceDs.getCellData(0, "susRecvSellRtnDrAmt")) + Number(ds_evidenceDs.getCellData(0, "susRecvSellAmt")) + Number(ds_evidenceDs.getCellData(0, "pldgAmt"))));
        ed_cashRtnAmt.setValue(ds_evidenceDs.getCellData(0, "cashRtnAmt"));
        ica_slipCloseYm.setValue(ds_evidenceDs.getCellData(0, "slipCloseYm")); //회계마감월
        ica_taxCloseYm.setValue(ds_evidenceDs.getCellData(0, "taxCloseYm")); //세무마감월

        if ($c.gus.cfIsNull(ds_evidenceDs.getCellData(0, "slipNo"))) {
            ed_summary.setValue(scwin.hid_summary);	// 매출항목	
            ed_goods.setValue(scwin.hid_goods);	    // 매출항목	
        } else {
            rd_receptClsCd.setDisabled(true);
        }

        if (ds_evidenceDs.getCellData(0, "hitekSendYn") == "Y") {
            await $c.gus.cfAlertMsg(["동부 하이텍에 전송된  기존 운임정보가 존재합니다."]);
        }
    }
};

scwin.sbm_DeleteCerti_submitdone = async function (e) {
    if(await $c.gus.cfAlertMsg(MSG_CM_INF_004)){
        scwin.saveflag = "TRUE";
        scwin.f_OnUnload(); 
    }
};

//-------------------------------------------------------------------------
// DataSet 이벤트
//-------------------------------------------------------------------------
scwin.ds_evidenceDs_ondataload = async function () {
	if (ds_evidenceDs.getRowCount() == 0 ){ 
		await $c.gus.cfAlertMsg("조회된 데이터가 없습니다.");
	}
};

scwin.ds_ctrt_ondataload = function () {
	if (ds_ctrt.getRowCount() == 0){ 
        totalRows.setValue(0);
	} else {
        totalRows.setValue(ds_ctrt.getRowCount());
    }
};
